import{_ as e,o as t,c as a,O as s}from"./chunks/framework.d5623306.js";const _=JSON.parse('{"title":"PhD Thesis","description":"","frontmatter":{"prev":false,"next":false,"image":"balatonkenese.jpg","caption":"Balatonkenese, Hungary, May 2019"},"headers":[],"relativePath":"research/phdthesis/index.md","filePath":"research/phdthesis/index.md"}'),r={name:"research/phdthesis/index.md"},i=s('<h1 id="phd-thesis" tabindex="-1">PhD Thesis <a class="header-anchor" href="#phd-thesis" aria-label="Permalink to &quot;PhD Thesis&quot;">​</a></h1><p>This section of the website gathers several resources related to the research I worked on for my PhD thesis. This latter is about <strong>formal analysis of human-machine interactions</strong>, a very broad subject.More precisely, this section contains a simplified and vulgarised description of my work, material used during several seminars, the tools developed during my thesis, and many other things.</p><p>I started this PhD thesis in January 2008 in the <a href="https://uclouvain.be/en/research-institutes/icteam/ingi" target="_blank" rel="noreferrer">Computer Science and Engineering Department</a> (INGI) which is part of the <a href="https://uclouvain.be/en/research-institutes/icteam" target="_blank" rel="noreferrer">Institute for Information and Communication Technologies, Electronics and Applied Mathematics</a> (ICTEAM), under the supervision of Prof. Charles Pecheur. I obtained my Phd thesis graduating from the <a href="https://www.uclouvain.be/en" target="_blank" rel="noreferrer">Université catholique de Louvain</a> in November 2013.</p>',3),n=[i];function o(h,c,d,l,p,u){return t(),a("div",null,n)}const f=e(r,[["render",o]]);export{_ as __pageData,f as default};
